enumeration_sql.sql:
WITH deg AS (
  SELECT node, count(*) AS degree FROM (
    SELECT n1 AS node FROM formula_edges UNION ALL SELECT n2 FROM formula_edges
  ) e GROUP BY node
)
SELECT width_bucket(degree, 1, 200, 20) AS degree_bucket,
       min(degree) AS min_deg, max(degree) AS max_deg, count(*) AS n_nodes
FROM deg GROUP BY 1 ORDER BY 1;
